// Normalize object keys — strips hidden chars (zero-width spaces, NBSP, BOM, etc.)
function cleanKeys(obj) {
  const clean = {};
  for (const key of Object.keys(obj)) {
    const normalKey = key.replace(/[\s\u00A0\u200B\u200C\u200D\uFEFF]+/g, '_').replace(/^_+|_+$/g, '').toLowerCase();
    clean[normalKey] = obj[key];
  }
  return clean;
}

// Load excluded companies from sheet (specific firm + enterprise names)
const excludedCompanies = $('Read Excluded Companies').all()
  .filter(r => r.json.company_name)
  .map(r => ({
    name: (r.json.company_name || '').toLowerCase().trim(),
    type: (r.json.type || 'excluded').toLowerCase().trim()
  }));

const combos = [];

for (const item of $input.all()) {
  const row = cleanKeys(item.json);

  const isActive = row.active === true || String(row.active).toLowerCase() === 'true';
  if (!isActive) continue;

  const roles = String(row.role_keywords || '').split(';').map(r => r.trim()).filter(Boolean);
  const locs = String(row.locations || '').split(';').map(l => l.trim()).filter(Boolean);
  const excludedKeywords = String(row.excluded_keywords || '').split(';').map(k => k.trim()).filter(Boolean);

  for (const role of roles) {
    for (const loc of locs) {
      combos.push({
        search_id: row.search_id || '',
        query: role,
        location: loc,
        employment_type: String(row.employment_type || 'FULLTIME').toUpperCase().replace(/\s+/g, ''),
        excluded_keywords: excludedKeywords,
        _excluded_companies: excludedCompanies
      });
    }
  }
}

return combos.map(c => ({ json: c }));

// Normalize JSearch response to common schema
const results = [];
const crypto = require('crypto');

for (const item of $input.all()) {
  const data = item.json;
  const jobs = data.data || [];

  for (const job of jobs) {
    const companyDomain = (job.employer_website || '').replace(/https?:\/\/(www\.)?/, '').split('/')[0].toLowerCase();
    const key = `${companyDomain}|${(job.job_title || '').toLowerCase()}|${(job.job_city || '').toLowerCase()}`;
    const opportunityId = crypto.createHash('md5').update(key).digest('hex').substring(0, 12);

    let employmentType = 'unknown';
    const jt = (job.job_employment_type || '').toUpperCase();
    if (jt.includes('CONTRACT')) employmentType = 'contract';
    else if (jt.includes('FULLTIME') || jt.includes('FULL_TIME')) employmentType = 'direct_hire';
    else if (jt.includes('PART')) employmentType = 'part_time';

    const skillKeywords = ['python','javascript','typescript','react','node','sql','java','go','rust','aws','azure','gcp','kubernetes','docker','terraform'];
    const skills = skillKeywords.filter(sk => JSON.stringify(job).toLowerCase().includes(sk)).join(', ');

    results.push({
      json: {
        opportunity_id: opportunityId,
        company_name: job.employer_name || '',
        company_domain: companyDomain,
        job_title: job.job_title || '',
        location: `${job.job_city || ''}, ${job.job_state || ''}`.trim().replace(/^,\s*/, ''),
        employment_type: employmentType,
        source_name: 'JSearch/RapidAPI',
        source_url: job.job_apply_link || job.job_google_link || '',
        posted_date: job.job_posted_at_datetime_utc || '',
        date_found: new Date().toISOString(),
        job_description: (job.job_description || '').substring(0, 2000),
        skills: skills,
        seniority: job.job_required_experience?.required_experience_in_months > 60 ? 'senior' : job.job_required_experience?.required_experience_in_months > 24 ? 'mid' : 'junior',
        match_score: 0,
        company_classification: '',
        company_classification_reason: '',
        status: 'discovered',
        _excluded_keywords: item.json._excluded_keywords || [],
        _excluded_company_types: item.json._excluded_company_types || []
      }
    });
  }
}

return results;

const results = [];

for (const item of $input.all()) {
  const job = { ...item.json };
  let score = 50;

  const text = `${job.job_title} ${job.job_description}`.toLowerCase();
  const title = job.job_title.toLowerCase();

  if (['engineer','developer','manager','director','analyst','architect','lead'].some(t => title.includes(t))) score += 15;
  if (['senior','sr.','lead','principal','staff','director','vp'].some(s => title.includes(s))) score += 10;
  if (job.source_url) score += 5;
  if (text.includes('remote') || text.includes('hybrid')) score += 5;

  const excluded = job._excluded_keywords || [];
  if (excluded.some(kw => text.includes(kw.toLowerCase()))) score -= 30;

  job.match_score = Math.min(100, Math.max(0, score));
  results.push({ json: job });
}

return results;

// Generic descriptors — hardcoded, these never need to change
const GENERIC_STAFFING_KEYWORDS = [
  'staffing','recruiting','recruitment','talent acquisition','headhunter',
  'executive search','placement agency','temp agency','contingent workforce',
  'msp','rpo','managed service provider','vendor management','contract staffing',
  'staff augmentation','workforce solutions'
];

const results = [];

for (const item of $input.all()) {
  const job = { ...item.json };
  const checkText = `${job.company_name} ${job.job_description}`.toLowerCase();

  // Sheet-based exclusions — specific company names (staffing firms + enterprises)
  const sheetExclusions = job._excluded_companies || [];

  // 1. Check generic staffing keywords
  const genericMatch = GENERIC_STAFFING_KEYWORDS.find(kw => checkText.includes(kw));

  // 2. Check sheet exclusions
  const sheetMatch = sheetExclusions.find(ex => ex.name && checkText.includes(ex.name));

  if (genericMatch) {
    job.pre_filter_result = 'staffing_firm';
    job.company_classification = 'staffing_firm';
    job.company_classification_reason = `Keyword match: "${genericMatch}"`;
  } else if (sheetMatch) {
    job.pre_filter_result = 'staffing_firm'; // routes to rejected path in Route by Pre-Filter
    job.company_classification = sheetMatch.type === 'enterprise' ? 'excluded_enterprise' : 'staffing_firm';
    job.company_classification_reason = `Sheet exclusion (${sheetMatch.type}): "${sheetMatch.name}"`;
  } else {
    const suspiciousPatterns = /(consulting|solutions|group|partners|services|associates|resources)$/i;
    job.pre_filter_result = suspiciousPatterns.test(job.company_name.trim()) ? 'unclear' : 'likely_direct';
  }

  results.push({ json: job });
}

return results;

// Restore original opportunity fields after OpenAI call replaced item.json
const results = [];
const originalItems = $('Preserve Pre-LLM Data').all();

for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  const orig = originalItems[i] ? originalItems[i].json : {};

  let company_classification = 'unclear';
  let company_classification_reason = 'LLM classification';

  try {
    const content = item.json.choices?.[0]?.message?.content || '{}';
    const parsed = JSON.parse(content.replace(/```json?/g,'').replace(/```/g,'').trim());
    company_classification = parsed.classification || 'unclear';
    company_classification_reason = parsed.reason || 'LLM classification';

    // Reject enterprise companies (over $100MM) â€” treated same as staffing firms
    if (parsed.company_size_tier === 'enterprise') {
      company_classification = 'staffing_firm';
      company_classification_reason = 'Enterprise company excluded: ' + (parsed.reason || 'revenue likely over $100MM');
    }
  } catch(e) {
    company_classification = 'unclear';
    company_classification_reason = 'Parse error';
  }

  results.push({ json: {
    ...orig,
    company_classification,
    company_classification_reason
  }});
}
return results;

// Explicitly tag these items as direct employer â€” no staffing keywords detected
return $input.all().map(item => ({
  json: {
    ...item.json,
    company_classification: 'direct_employer',
    company_classification_reason: 'Keyword pre-filter: no staffing keywords detected'
  }
}));

const results = [];
const seen = new Set();

for (const item of $input.all()) {
  const job = { ...item.json };
  const key = `${(job.company_domain||'').toLowerCase()}|${(job.job_title||'').toLowerCase()}|${(job.location||'').toLowerCase()}`;
  job._dedup_key = key;
  if (!seen.has(key)) {
    seen.add(key);
    job.status = 'qualified';
    results.push({ json: job });
  }
}
return results;

// Google Sheets append returns minimal fields â€” re-merge with full opportunity data
const dedupItems = $('Dedup Check').all();
return $input.all().map((item, idx) => {
  const original = dedupItems[idx] ? dedupItems[idx].json : {};
  return { json: { ...original, ...item.json } };
})

// Filter out-of-state jobs from raw JSearch responses
// Handles both 2-letter state codes (CA) and full names (California)
// Remote jobs pass through for manual review/approval

const STATE_NAMES = {
  AL:'Alabama',AK:'Alaska',AZ:'Arizona',AR:'Arkansas',CA:'California',
  CO:'Colorado',CT:'Connecticut',DE:'Delaware',FL:'Florida',GA:'Georgia',
  HI:'Hawaii',ID:'Idaho',IL:'Illinois',IN:'Indiana',IA:'Iowa',
  KS:'Kansas',KY:'Kentucky',LA:'Louisiana',ME:'Maine',MD:'Maryland',
  MA:'Massachusetts',MI:'Michigan',MN:'Minnesota',MS:'Mississippi',MO:'Missouri',
  MT:'Montana',NE:'Nebraska',NV:'Nevada',NH:'New Hampshire',NJ:'New Jersey',
  NM:'New Mexico',NY:'New York',NC:'North Carolina',ND:'North Dakota',OH:'Ohio',
  OK:'Oklahoma',OR:'Oregon',PA:'Pennsylvania',RI:'Rhode Island',SC:'South Carolina',
  SD:'South Dakota',TN:'Tennessee',TX:'Texas',UT:'Utah',VT:'Vermont',
  VA:'Virginia',WA:'Washington',WV:'West Virginia',WI:'Wisconsin',WY:'Wyoming'
};

const buildSearchItems = $('Build Search Combinations').all();
const results = [];

for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  const combo = buildSearchItems[i] ? buildSearchItems[i].json : {};

  // Extract 2-letter state code from location (e.g. 'Los Angeles, CA' -> 'CA')
  const targetLocation = combo.location || '';
  const stateMatch = targetLocation.match(/\b([A-Z]{2})\b/);
  const targetStateCode = stateMatch ? stateMatch[1] : '';
  const targetStateName = targetStateCode ? (STATE_NAMES[targetStateCode] || '') : '';

  const jobs = item.json.data || [];
  const originalCount = jobs.length;

  const filtered = jobs.filter(job => {
    // Only drop if job_state is non-empty AND explicitly a different state
    // Compare against both 2-letter code (CA) and full name (California)
    if (targetStateCode && job.job_state) {
      const s = job.job_state.trim();
      if (s !== targetStateCode && s !== targetStateName) return false;
    }
    return true;
  });

  results.push({
    json: {
      ...item.json,
      data: filtered,
      _original_count: originalCount,
      _filtered_count: filtered.length
    }
  });
}

return results;

